const body = $json.body || $json;
const evt = body.event;
const actor = body.actor || {};
const actorName = actor.name || 'Jemand';

let emoji = '📋';
let text = '';
let channel = '{{ $env.SLACK_NOTIFY_CHANNEL || "C0A7LTX603Z" }}';
let priority = 'normal';

switch(evt) {
  case 'aufgabe_zugewiesen':
    emoji = '📋';
    text = `*${actorName}* hat eine Aufgabe zugewiesen an *${body.fuer?.name || '?'}*:\n> ${body.aufgabe || '?'}${body.prio ? ' (' + body.prio + ')' : ''}${body.dl ? ' — fällig: ' + body.dl : ''}`;
    break;

  case 'meilenstein_erledigt':
    emoji = '🎯';
    text = `*${actorName}* hat einen Meilenstein erreicht! 🎉\n> ✅ *${body.meilenstein || '?'}*${body.ziel ? '\n> Ziel: ' + body.ziel : ''}`;
    priority = 'high';
    break;

  case 'big3_erledigt':
    emoji = '✅';
    text = `*${actorName}* hat ein Big-3-Ziel erledigt (KW ${body.kw || '?'}):\n> ✅ ${body.big3 || '?'}`;
    break;

  case 'blocker':
    emoji = '⚠️';
    text = `*${actorName}* meldet einen Blocker:\n> ⚠️ ${body.blocker || '?'}`;
    priority = 'high';
    break;

  default:
    text = `${actorName}: Unbekanntes Event (${evt})`;
}

return [{
  json: {
    channel,
    text: `${emoji} ${text}`,
    event: evt,
    priority
  }
}];
